  create policy "Users can read scores of own matches"
  on "public"."match_scores"
  as permissive
  for select
  to authenticated
using ((EXISTS ( SELECT 1
   FROM (public.matches m
     JOIN public.profiles p ON (((p.id = m.player1_id) OR (p.id = m.player2_id))))
  WHERE ((m.id = match_scores.match_id) AND (p.auth_user_id = auth.uid())))));



  create policy "Users can submit scores for own matches"
  on "public"."match_scores"
  as permissive
  for insert
  to authenticated
with check ((EXISTS ( SELECT 1
   FROM (public.matches m
     JOIN public.profiles p ON (((p.id = m.player1_id) OR (p.id = m.player2_id))))
  WHERE ((m.id = match_scores.match_id) AND (p.auth_user_id = auth.uid())))));



  create policy "Users can read own matches"
  on "public"."matches"
  as permissive
  for select
  to authenticated
using ((EXISTS ( SELECT 1
   FROM public.profiles p
  WHERE ((p.auth_user_id = auth.uid()) AND ((p.id = matches.player1_id) OR (p.id = matches.player2_id))))));



  create policy "Users can read own profile"
  on "public"."profiles"
  as permissive
  for select
  to authenticated
using ((auth.uid() = auth_user_id));



  create policy "Users can update own profile"
  on "public"."profiles"
  as permissive
  for update
  to authenticated
using ((auth.uid() = auth_user_id))
with check ((auth.uid() = auth_user_id));


CREATE TRIGGER check_match_score_winner BEFORE INSERT OR UPDATE ON public.match_scores FOR EACH ROW EXECUTE FUNCTION public.validate_match_score_winner();


